9399       cast<BranchInst>(VecEpilogueIterationCountCheck->getTerminator())
9400           ->getSuccessor(1);
9401   // Adjust the control flow taking the state info from the main loop
9402   // vectorization into account.
9403   assert(EPI.MainLoopIterationCountCheck && EPI.EpilogueIterationCountCheck &&
9404          "expected this to be saved from the previous pass.");
9405   DomTreeUpdater DTU(DT, DomTreeUpdater::UpdateStrategy::Eager);
9406   EPI.MainLoopIterationCountCheck->getTerminator()->replaceUsesOfWith(
9407       VecEpilogueIterationCountCheck, VecEpiloguePreHeader);
9408 
9409   DTU.applyUpdates({{DominatorTree::Delete, EPI.MainLoopIterationCountCheck,
9410                      VecEpilogueIterationCountCheck},
9411                     {DominatorTree::Insert, EPI.MainLoopIterationCountCheck,
9412                      VecEpiloguePreHeader}});
9413 
9414   BasicBlock *ScalarPH =
9415       cast<VPIRBasicBlock>(EpiPlan.getScalarPreheader())->getIRBasicBlock();
