7326 // If \p EpiResumePhiR is resume VPPhi for a reduction when vectorizing the
7327 // epilog loop, fix the reduction's scalar PHI node by adding the incoming value
7328 // from the main vector loop.
7329 static void fixReductionScalarResumeWhenVectorizingEpilog(
7330     VPPhi *EpiResumePhiR, PHINode &EpiResumePhi, BasicBlock *BypassBlock) {
7331   using namespace VPlanPatternMatch;
7332   // Get the VPInstruction computing the reduction result in the middle block.
7333   // The first operand may not be from the middle block if it is not connected
7334   // to the scalar preheader. In that case, there's nothing to fix.
7335   VPValue *Incoming = EpiResumePhiR->getOperand(0);
7336   match(Incoming, VPlanPatternMatch::m_ZExtOrSExt(
7337                       VPlanPatternMatch::m_VPValue(Incoming)));
7338   auto *EpiRedResult = dyn_cast<VPInstruction>(Incoming);
7339   if (!EpiRedResult)
7340     return;
7341 
7342   VPValue *BackedgeVal;
7343   bool IsFindIV = false;
7344   if (EpiRedResult->getOpcode() == VPInstruction::ComputeAnyOfResult ||
7345       EpiRedResult->getOpcode() == VPInstruction::ComputeReductionResult)
7346     BackedgeVal = EpiRedResult->getOperand(EpiRedResult->getNumOperands() - 1);
7347   else if (matchFindIVResult(EpiRedResult, m_VPValue(BackedgeVal), m_VPValue()))
7348     IsFindIV = true;
7349   else
7350     return;
7351 
7352   auto *EpiRedHeaderPhi = cast_if_present<VPReductionPHIRecipe>(
7353       vputils::findRecipe(BackedgeVal, IsaPred<VPReductionPHIRecipe>));
7354   if (!EpiRedHeaderPhi) {
7355     match(BackedgeVal,
7356           VPlanPatternMatch::m_Select(VPlanPatternMatch::m_VPValue(),
7357                                       VPlanPatternMatch::m_VPValue(BackedgeVal),
7358                                       VPlanPatternMatch::m_VPValue()));
7359     EpiRedHeaderPhi = cast_if_present<VPReductionPHIRecipe>(
7360         vputils::findRecipe(BackedgeVal, IsaPred<VPReductionPHIRecipe>));
7361     if (!EpiRedHeaderPhi)
7362       return;
7363   }
7364 
7365   Value *MainResumeValue;
7366   if (auto *VPI = dyn_cast<VPInstruction>(EpiRedHeaderPhi->getStartValue())) {
7367     assert((VPI->getOpcode() == VPInstruction::Broadcast ||
7368             VPI->getOpcode() == VPInstruction::ReductionStartVector) &&
7369            "unexpected start recipe");
7370     MainResumeValue = VPI->getOperand(0)->getUnderlyingValue();
7371   } else
7372     MainResumeValue = EpiRedHeaderPhi->getStartValue()->getUnderlyingValue();
7373   if (EpiRedResult->getOpcode() == VPInstruction::ComputeAnyOfResult) {
7374     [[maybe_unused]] Value *StartV =
7375         EpiRedResult->getOperand(0)->getLiveInIRValue();
7376     auto *Cmp = cast<ICmpInst>(MainResumeValue);
7377     assert(Cmp->getPredicate() == CmpInst::ICMP_NE &&
7378            "AnyOf expected to start with ICMP_NE");
7379     assert(Cmp->getOperand(1) == StartV &&
7380            "AnyOf expected to start by comparing main resume value to original "
7381            "start value");
7382     MainResumeValue = Cmp->getOperand(0);
7383   } else if (IsFindIV) {
7384     MainResumeValue = cast<SelectInst>(MainResumeValue)->getFalseValue();
7385   }
7386   PHINode *MainResumePhi = cast<PHINode>(MainResumeValue);
7387 
7388   // When fixing reductions in the epilogue loop we should already have
7389   // created a bc.merge.rdx Phi after the main vector body. Ensure that we carry
7390   // over the incoming values correctly.
7391   EpiResumePhi.setIncomingValueForBlock(
7392       BypassBlock, MainResumePhi->getIncomingValueForBlock(BypassBlock));
7393 }
