 9923 LoopVectorizeResult LoopVectorizePass::runImpl(Function &F) {
 9924 
 9925   // Don't attempt if
 9926   // 1. the target claims to have no vector registers, and
 9927   // 2. interleaving won't help ILP.
 9928   //
 9929   // The second condition is necessary because, even if the target has no
 9930   // vector registers, loop vectorization may still enable scalar
 9931   // interleaving.
 9932   if (!TTI->getNumberOfRegisters(TTI->getRegisterClassForType(true)) &&
 9933       TTI->getMaxInterleaveFactor(ElementCount::getFixed(1)) < 2)
 9934     return LoopVectorizeResult(false, false);
 9935 
 9936   bool Changed = false, CFGChanged = false;
 9937 
 9938   // The vectorizer requires loops to be in simplified form.
 9939   // Since simplification may add new inner loops, it has to run before the
 9940   // legality and profitability checks. This means running the loop vectorizer
 9941   // will simplify all loops, regardless of whether anything end up being
 9942   // vectorized.
 9943   for (const auto &L : *LI)
 9944     Changed |= CFGChanged |=
 9945         simplifyLoop(L, DT, LI, SE, AC, nullptr, false /* PreserveLCSSA */);
 9946 
 9947   // Build up a worklist of inner-loops to vectorize. This is necessary as
 9948   // the act of vectorizing or partially unrolling a loop creates new loops
 9949   // and can invalidate iterators across the loops.
 9950   SmallVector<Loop *, 8> Worklist;
 9951 
 9952   for (Loop *L : *LI)
 9953     collectSupportedLoops(*L, LI, ORE, Worklist);
 9954 
 9955   LoopsAnalyzed += Worklist.size();
 9956 
 9957   // Now walk the identified inner loops.
 9958   while (!Worklist.empty()) {
 9959     Loop *L = Worklist.pop_back_val();
 9960 
 9961     // For the inner loops we actually process, form LCSSA to simplify the
 9962     // transform.
 9963     Changed |= formLCSSARecursively(*L, *DT, LI, SE);
 9964 
 9965     Changed |= CFGChanged |= processLoop(L);
 9966 
 9967     if (Changed) {
 9968       LAIs->clear();
 9969 
 9970 #ifndef NDEBUG
 9971       if (VerifySCEV)
 9972         SE->verify();
 9973 #endif
 9974     }
 9975   }
 9976 
 9977   // Process each loop nest in the function.
 9978   return LoopVectorizeResult(Changed, CFGChanged);
 9979 }
