 9981 PreservedAnalyses LoopVectorizePass::run(Function &F,
 9982                                          FunctionAnalysisManager &AM) {
 9983   LI = &AM.getResult<LoopAnalysis>(F);
 9984   // There are no loops in the function. Return before computing other
 9985   // expensive analyses.
 9986   if (LI->empty())
 9987     return PreservedAnalyses::all();
 9988   SE = &AM.getResult<ScalarEvolutionAnalysis>(F);
 9989   TTI = &AM.getResult<TargetIRAnalysis>(F);
 9990   DT = &AM.getResult<DominatorTreeAnalysis>(F);
 9991   TLI = &AM.getResult<TargetLibraryAnalysis>(F);
 9992   AC = &AM.getResult<AssumptionAnalysis>(F);
 9993   DB = &AM.getResult<DemandedBitsAnalysis>(F);
 9994   ORE = &AM.getResult<OptimizationRemarkEmitterAnalysis>(F);
 9995   LAIs = &AM.getResult<LoopAccessAnalysis>(F);
 9996   AA = &AM.getResult<AAManager>(F);
 9997 
 9998   auto &MAMProxy = AM.getResult<ModuleAnalysisManagerFunctionProxy>(F);
 9999   PSI = MAMProxy.getCachedResult<ProfileSummaryAnalysis>(*F.getParent());
10000   GetBFI = [&AM, &F]() -> BlockFrequencyInfo & {
10001     return AM.getResult<BlockFrequencyAnalysis>(F);
10002   };
10003   LoopVectorizeResult Result = runImpl(F);
10004   if (!Result.MadeAnyChange)
10005     return PreservedAnalyses::all();
10006   PreservedAnalyses PA;
10007 
10008   if (isAssignmentTrackingEnabled(*F.getParent())) {
10009     for (auto &BB : F)
10010       RemoveRedundantDbgInstrs(&BB);
10011   }
10012 
10013   PA.preserve<LoopAnalysis>();
10014   PA.preserve<DominatorTreeAnalysis>();
10015   PA.preserve<ScalarEvolutionAnalysis>();
10016   PA.preserve<LoopAccessAnalysis>();
10017 
10018   if (Result.MadeCFGChange) {
10019     // Making CFG changes likely means a loop got vectorized. Indicate that
10020     // extra simplification passes should be run.
10021     // TODO: MadeCFGChanges is not a prefect proxy. Extra passes should only
10022     // be run if runtime checks have been added.
10023     AM.getResult<ShouldRunExtraVectorPasses>(F);
10024     PA.preserve<ShouldRunExtraVectorPasses>();
10025   } else {
10026     PA.preserveSet<CFGAnalyses>();
10027   }
10028   return PA;
10029 }
