9365   for (const auto &[IVPhi, II] : LVL.getInductionVars()) {
9366     Value *IncomingFromPH = IVPhi->getIncomingValueForBlock(PH);
9367     Value *V = createInductionAdditionalBypassValues(
9368         IVPhi, II, BypassBuilder, ExpandedSCEVs, MainVectorTripCount,
9369         LVL.getPrimaryInduction());
9370 
9371     if (auto *Inc = dyn_cast<PHINode>(IncomingFromPH)) {
9372       // TODO: Directly add as extra operand to the VPResumePHI recipe.
