9473   // VecEpilogueIterationCountCheck conditionally skips over the epilogue loop
9474   // after executing the main loop. We need to update the resume values of
9475   // inductions and reductions during epilogue vectorization.
9476   fixScalarResumeValuesFromBypass(VecEpilogueIterationCountCheck, L, EpiPlan,
9477                                   LVL, ExpandedSCEVs, EPI.VectorTripCount);
